UPDATE d_order_ticket_user
SET order_status = #{transition.toStatusCode},
    edit_time = #{transition.eventTime}

        , cancel_order_time = #{transition.eventTime}


        , pay_order_time = #{transition.eventTime}


        , pay_order_price = order_price

WHERE order_number = #{transition.orderNumber}
  AND order_status = #{transition.fromStatusCode}
  AND status = 1

mapper.select:
SELECT order_number
FROM d_order
WHERE order_status = #{unpaidStatus}
  AND expire_time <= #{now}
  AND status = 1
ORDER BY expire_time ASC
LIMIT #{limit}
